import React from 'react';
import { designGalleryImages } from '../designGallery/loadDesignGalleryImages';
import { designGalleryPublicMedia } from '../designGallery/designGalleryPublicMedia';
import DesignGalleryVideo from './DesignGalleryVideo';

export default function DesignGallery() {
  const items = [
    ...designGalleryImages.map((img) => ({ kind: 'image', ...img })),
    ...designGalleryPublicMedia.map((entry) => ({ kind: entry.type === 'video' ? 'video' : 'image', ...entry })),
  ];

  if (!items.length) {
    return (
      <div className="design-gallery design-gallery--empty">
        <p>
          Add image files to <span className="design-gallery__path">src/assets/design-gallery</span> (PNG, JPG,
          WebP, GIF, or SVG), or large GIFs/videos under{' '}
          <span className="design-gallery__path">public/images/design-gallery</span> (registered in{' '}
          <span className="design-gallery__path">src/designGallery/designGalleryPublicMedia.js</span>), then save
          and refresh the dev server.
        </p>
      </div>
    );
  }

  return (
    <div className="design-gallery" role="list">
      {items.map((item, i) => (
        <figure
          key={`${item.kind}-${item.src}-${i}`}
          className={`design-gallery__item design-gallery__item--v${(i % 7) + 1}`}
          role="listitem"
          data-aos="fade-up"
          data-aos-once
          data-aos-delay={Math.min((i % 6) * 45, 200)}
        >
          <div className="design-gallery__frame">
            {item.kind === 'video' ? (
              <DesignGalleryVideo
                src={item.src}
                alt={item.alt}
                loopStart={item.loopStart}
                loopEnd={item.loopEnd}
              />
            ) : (
              <img src={item.src} alt={item.alt} loading="lazy" decoding="async" />
            )}
          </div>
        </figure>
      ))}
    </div>
  );
}
